import React from "react"
import { Logo } from "./images.js"
import { StaticQuery, graphql } from "gatsby"
import Img from "gatsby-image"
import Fade from "react-reveal/Fade"

const Upwork = () => (
  <StaticQuery
    query={graphql`
      query {
        placeholderImage: file(relativePath: { eq: "lumerb-upwork.png" }) {
          childImageSharp {
            fluid(maxWidth: 300) {
              ...GatsbyImageSharpFluid
            }
          }
        }
      }
    `}
    render={data => <Img style ={{width: "90px", margin: "0px auto", marginTop: "12px"}} fluid={data.placeholderImage.childImageSharp.fluid} />}
  />
)

const Hero = ()=>{

  return(

    <div name = "home" className = "lumerb-heading">
      <div className = "TextContainer">
        <Fade top duration={1000}>
          <Logo />
          <h1>lumerb</h1>
        </Fade>
        <Fade right delay={1000}>
        <p style={{lineHeight: "18px", marginTop: "8px"}}>Graphic Design and Web Development</p>
        </Fade>
        <Fade left delay={1200}>
          <p style={{marginTop: "20px"}}>View my work via</p>
        </Fade>
        <ul className="icons">

        <Fade bottom delay={2000}>
          <li><a href="https://www.behance.net/lumerbdesigns" className="fab fa-behance alt" target = "_blank" rel="noopener noreferrer"><span className="label"></span></a></li>
          <li><a href="https://www.instagram.com/lumerb_designs" className="fab fa-instagram alt" target = "_blank" rel="noopener noreferrer"><span className="label"></span></a></li>
          <li><a href="https://github.com/lumerb" className="fab fa-github alt" target = "_blank" rel="noopener noreferrer"><span className="label" ></span></a></li>
          <li><a href="https://www.linkedin.com/in/lumerb" className="fab fa-linkedin alt" target = "_blank" rel="noopener noreferrer"><span className="label"></span></a></li>
          <li><a href="https://twitter.com/lumerbcode" className="fab fa-twitter alt" target = "_blank" rel="noopener noreferrer"><span className="label" ></span></a></li>
          </Fade>
        </ul>
        <Fade bottom delay={3000}>
        <a id = "upwork" href="https://www.upwork.com/fl/lumerb" target = "_blank" rel="noopener noreferrer"><Upwork /></a>
        </Fade>
      </div>
    </div>

  )
}


export default Hero
